authentication.example_nodejs_fetch:
import crypto from 'node:crypto';
const API_KEY = Deno.env.get('BYBIT_API_KEY')!;
const API_SECRET = Deno.env.get('BYBIT_API_SECRET')!;
const BASE = Deno.env.get('BYBIT_BASE_URL')!;
const RECV = '5000';
export async function bybitSignedPost(path: string, body: object) {
  const ts = Date.now().toString();
  const raw = JSON.stringify(body);
  const payload = ts + API_KEY + RECV + raw;
  const sign = crypto.createHmac('sha256', API_SECRET).update(payload).digest('hex');
  const res = await fetch(BASE + path, {
    method: 'POST',
    headers: {
      'X-BAPI-API-KEY': API_KEY,
      'X-BAPI-TIMESTAMP': ts,
      'X-BAPI-RECV-WINDOW': RECV,
      'X-BAPI-SIGN': sign,
      'Content-Type': 'application/json',
    },
    body: raw,
  });
  return res.json();
}

